				ResultRev:        "abc123",
			},
		},
		{
			name: "quota",
			report: ExecuteBeadReport{
				Status:        ExecuteBeadStatusExecutionFailed,
				OutcomeReason: "quota",
				BaseRev:       "abc123",
				ResultRev:     "abc123",
			},
		},
		{
			name: "transport",
			report: ExecuteBeadReport{
				Status:        ExecuteBeadStatusExecutionFailed,
				OutcomeReason: "transport",
				BaseRev:       "abc123",
				ResultRev:     "abc123",
			},
		},
		{
			name: "auth_tool_setup",
			report: ExecuteBeadReport{
				Status:        ExecuteBeadStatusExecutionFailed,
				OutcomeReason: FailureModeAuthError,
				BaseRev:       "abc123",
				ResultRev:     "abc123",
			},
		},
		{
			name: "review_error",
			report: ExecuteBeadReport{
				Status:    ExecuteBeadStatusReviewMalfunction,
