	assert.Contains(t, event.Body, "predicted_power=82")
	assert.Contains(t, event.Body, "predicted_speed_tps=35.5")
	assert.Contains(t, event.Body, "predicted_cost_usd_per_1k_tokens=0.012345 source=catalog")
}

